export enum ReplicationMethod {
  PHYSICAL = 'Physical',
  SYNTHETIC = 'Synthetic',
}

export enum DistributionPolicy {
  ACCUMULATING = 'Accumulating',
  DISTRIBUTING = 'Distributing',
}

export interface ETF {
  isin: string;
  ticker: string;
  name: string;
  issuer: string;
  ter: number; // Total Expense Ratio as percentage (e.g., 0.07)
  aum: number; // Assets Under Management in Millions EUR
  currency: string;
  domicile: string;
  replication: ReplicationMethod;
  distribution: DistributionPolicy;
  holdingsCount: number;
  topHoldings: string[];
  description: string;
}

export interface Broker {
  id: string;
  name: string;
  country: string;
  commissionType: 'Fixed' | 'Variable' | 'Zero';
  commissionRate: number; // percentage
  minCommission: number; // in EUR
  currencyConversionFee: number; // percentage
  isAvailable: boolean;
  notes?: string;
}

export interface ProjectionData {
  year: number;
  etf1Value: number;
  etf2Value?: number;
}

/**
 * AlphaETF Financial Metrics Engine
 * Provides calculation logic for cost projection and tracking difference estimates.
 */

// Calculate compound growth with costs subtracted
export const calculateCompoundGrowth = (
  initialInvestment: number,
  annualReturn: number, // e.g. 0.07 for 7%
  ter: number, // e.g. 0.002 for 0.2%
  years: number
): number => {
  const netReturn = annualReturn - ter;
  return initialInvestment * Math.pow(1 + netReturn, years);
};

// Calculate total cost of ownership over a period
export const calculateTotalCost = (
  initialInvestment: number,
  annualReturn: number,
  ter: number,
  years: number
): number => {
  const grossValue = initialInvestment * Math.pow(1 + annualReturn, years);
  const netValue = calculateCompoundGrowth(initialInvestment, annualReturn, ter, years);
  return grossValue - netValue;
};

// Estimate simple tracking difference impact
export const estimateTrackingDifferenceImpact = (
  ter: number,
  avgTd: number // Average Tracking Difference
): number => {
  // Simplified model: Real Cost = TER + TD
  return ter + avgTd;
};

export const generateProjectionData = (
  etf1Ter: number,
  etf2Ter: number,
  years: number = 20,
  initialInvestment: number = 10000,
  assumedReturn: number = 0.07
) => {
  const data = [];
  for (let i = 0; i <= years; i++) {
    data.push({
      year: i,
      etf1Value: Math.round(calculateCompoundGrowth(initialInvestment, assumedReturn, etf1Ter / 100, i)),
      etf2Value: Math.round(calculateCompoundGrowth(initialInvestment, assumedReturn, etf2Ter / 100, i)),
    });
  }
  return data;
};

import { Broker, ETF } from '../types';

/**
 * Broker Mapper Module
 * Implements a simplified Strategy Pattern to determine broker availability and fees
 * based on ETF domicile and specific broker rules (e.g., XTB, mBank, Bossa).
 */

const BROKERS: Omit<Broker, 'isAvailable' | 'notes'>[] = [
  {
    id: 'xtb',
    name: 'XTB',
    country: 'Poland',
    commissionType: 'Zero',
    commissionRate: 0,
    minCommission: 0,
    currencyConversionFee: 0.5,
  },
  {
    id: 'mbank',
    name: 'mBank (eMakler)',
    country: 'Poland',
    commissionType: 'Variable',
    commissionRate: 0.29,
    minCommission: 5, // 5 PLN roughly 1.15 EUR
    currencyConversionFee: 0.1,
  },
  {
    id: 'bossa',
    name: 'BOŚ (Bossa)',
    country: 'Poland',
    commissionType: 'Variable',
    commissionRate: 0.29,
    minCommission: 5,
    currencyConversionFee: 0.1, // Depends on account type
  },
  {
    id: 'degiro',
    name: 'Degiro',
    country: 'Netherlands',
    commissionType: 'Fixed',
    commissionRate: 0,
    minCommission: 1, // Core selection is free, others 1 EUR
    currencyConversionFee: 0.25,
  },
  {
    id: 'ibkr',
    name: 'Interactive Brokers',
    country: 'USA/Ireland',
    commissionType: 'Variable',
    commissionRate: 0.05,
    minCommission: 1.25,
    currencyConversionFee: 0.002, // Very low spot rate
  }
];

export const getBrokersForEtf = (etf: ETF): Broker[] => {
  return BROKERS.map(broker => {
    let isAvailable = true;
    let notes = 'Available for trading.';

    // Rule 1: US Domiciled ETFs are generally not available in EU to retail (PRIIPs)
    // In our mock data, all are UCITS (IE/LU), so they are fine.
    // But let's add a fictional check.
    if (!etf.name.includes('UCITS') && broker.country !== 'USA') {
      isAvailable = false;
      notes = 'Not PRIIPs compliant. Unavailable for EU retail investors.';
    }

    // Rule 2: Specific availability logic (Mock)
    if (broker.id === 'mbank' && etf.issuer === 'Amundi') {
      // Just a mock rule to show variation
      notes = 'Available. Special promo: 0% commision on Amundi for >100 EUR orders.';
    }

    if (broker.id === 'degiro' && etf.ticker === 'VWCE') {
       notes = 'Part of Core Selection (Free trading conditions apply).';
    }

    return {
      ...broker,
      isAvailable,
      notes
    };
  });
};

import { GoogleGenAI } from '@google/genai';
import { ETF } from '../types';

/**
 * AI Analyser Module
 * Handles communication with Google Gemini API to generate investment insights.
 */

// Initialize client securely - strictly uses process.env.API_KEY
// Note: In a real production app, this call might be proxied through a backend to keep the key secret,
// but for this demo, we use the client-side SDK as per instructions.
const getClient = () => {
    // Safety check - usually handled by build system
    if (!process.env.API_KEY) {
        console.warn("API Key is missing. AI features will not work.");
    }
    return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
}

export const analyzeEtfComparison = async (etf1: ETF, etf2: ETF): Promise<string> => {
  const client = getClient();

  const prompt = `
    You are a Senior Investment Analyst and Tax Specialist.
    Compare the following two ETFs for a long-term (20+ years) buy-and-hold portfolio for a European investor.

    ETF A:
    - Name: ${etf1.name} (${etf1.ticker})
    - ISIN: ${etf1.isin}
    - TER: ${etf1.ter}%
    - Domicile: ${etf1.domicile}
    - Replication: ${etf1.replication}
    - Distribution: ${etf1.distribution}
    - Top Holdings: ${etf1.topHoldings.join(', ')}

    ETF B:
    - Name: ${etf2.name} (${etf2.ticker})
    - ISIN: ${etf2.isin}
    - TER: ${etf2.ter}%
    - Domicile: ${etf2.domicile}
    - Replication: ${etf2.replication}
    - Distribution: ${etf2.distribution}
    - Top Holdings: ${etf2.topHoldings.join(', ')}

    Please provide a structured Markdown response covering:
    1. **Cost Analysis**: Impact of TER difference over 20 years.
    2. **Tax Efficiency**: Consider Domicile (Ireland vs Lux) and withholding tax implications for US equities (if applicable).
    3. **Structure & Risk**: Physical vs Synthetic replication risks.
    4. **Verdict**: Which fund fits better for a long-term compound growth portfolio?

    Keep the tone professional, concise, and objective.
  `;

  try {
    const response = await client.models.generateContent({
      model: 'gemini-3-flash-preview', // Using Flash for speed as per 'Basic Text Tasks' guidelines
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 } // Disable thinking for faster response on standard queries
      }
    });

    return response.text || "Could not generate analysis.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return `**Error generating insights.**\n\nPlease check your API key or try again later.\n\nTechnical details: ${error instanceof Error ? error.message : String(error)}`;
  }
};

export const getSingleEtfInsight = async (etf: ETF): Promise<string> => {
    const client = getClient();
    const prompt = `
        Analyze the ETF ${etf.name} (${etf.ticker}). 
        Explain its replication method (${etf.replication}) and what it means for a retail investor in simple terms.
        Is the TER of ${etf.ter}% competitive for this asset class?
    `;

    try {
        const response = await client.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
        });
        return response.text || "No insights available.";
    } catch (error) {
         return "AI Service temporarily unavailable.";
    }
}

