    if (selectedEtfs.find(e => e.isin === etf.isin)) {
      setSelectedEtfs(selectedEtfs.filter(e => e.isin !== etf.isin));
      setAiAnalysis(''); // Clear analysis if selection changes
    } else {
      if (selectedEtfs.length < 2) {
        setSelectedEtfs([...selectedEtfs, etf]);
        setAiAnalysis('');
      } else {
        // Replace the oldest selection if trying to add a 3rd
        setSelectedEtfs([selectedEtfs[1], etf]);
        setAiAnalysis('');
      }
    }
  };

  const runAnalysis = async () => {
    if (selectedEtfs.length !== 2) return;
    setIsAnalyzing(true);
    const result = await analyzeEtfComparison(selectedEtfs[0], selectedEtfs[1]);
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

