    if (selectedEtfs.length === 0) return [];

    // Get brokers for the first ETF
    const brokers = getBrokersForEtf(selectedEtfs[0]);
    return brokers;
  };

  const chartData = selectedEtfs.length > 0 
    ? generateProjectionData(
        selectedEtfs[0].ter, 
        selectedEtfs.length > 1 ? selectedEtfs[1].ter : 0,
        20
