  SYNTHETIC = 'Synthetic',
}

export enum DistributionPolicy {
  ACCUMULATING = 'Accumulating',
  DISTRIBUTING = 'Distributing',
}

export type TimeRange = '1M' | '1Y' | '3Y' | '5Y';

export interface ETF {
  isin: string;
  ticker: string;
  name: string;
  issuer: string;
  ter: number; // Total Expense Ratio as percentage
  aum: number; // Assets Under Management in Millions EUR
  currency: string;
  domicile: string;
  replication: ReplicationMethod;
  distribution: DistributionPolicy;
  holdingsCount: number;
  topHoldings: string[];
  description: string;
  // Financial characteristics for simulation
  baseAnnualReturn: number; // e.g. 0.08 for 8%
  volatility: number; // Standard deviation for simulation
  dividendYield: number; // e.g. 0.02 for 2% (0 if accumulating)
}

export interface Broker {
  id: string;
