  country: string;
  commissionType: 'Fixed' | 'Variable' | 'Zero';
  commissionRate: number; // percentage
  minCommission: number; // in EUR
  currencyConversionFee: number; // percentage
  isAvailable: boolean;
  notes?: string;
}

export interface ChartPoint {
  date: string;
  etf1Value: number;
  etf2Value?: number;
}

import { ETF, TimeRange, ChartPoint, DistributionPolicy } from '../types';

/**
 * AlphaETF Financial Metrics Engine
 */

const getDaysForRange = (range: TimeRange): number => {
  switch (range) {
    case '1M': return 21; // Trading days
    case '1Y': return 252;
    case '3Y': return 252 * 3;
    case '5Y': return 252 * 5;
    default: return 252;
  }
};

/**
 * Simulates historical price data using Geometric Brownian Motion (GBM).
 * This creates a realistic "jagged" stock chart rather than a straight line.
 * 
 * @param etf The ETF to simulate
 * @param range Time range
 * @param includeDividends If true, assumes dividends are reinvested (Total Return). If false and distributing, simulates Price Return (lower).
 */
export const generateHistoricalData = (
  etf1: ETF,
  etf2: ETF | null,
  range: TimeRange,
  includeDividends: boolean
): ChartPoint[] => {
  const days = getDaysForRange(range);
  const data: ChartPoint[] = [];
  const now = new Date();

  // Starting value normalized to 10,000 EUR
  let val1 = 10000;
  let val2 = etf2 ? 10000 : 0;

  // We generate backwards from today
  // But for the array, we want chronological order, so we generate forward from (Now - Range)

  const startDate = new Date();
  if (range === '1M') startDate.setMonth(now.getMonth() - 1);
  if (range === '1Y') startDate.setFullYear(now.getFullYear() - 1);
  if (range === '3Y') startDate.setFullYear(now.getFullYear() - 3);
  if (range === '5Y') startDate.setFullYear(now.getFullYear() - 5);

  // Daily parameters
  // Annual Return / 252
  // We subtract TER daily
  const dailyTer1 = etf1.ter / 100 / 252;
  const dailyTer2 = etf2 ? etf2.ter / 100 / 252 : 0;

  // Handling Dividends logic
  // If includeDividends is TRUE: We use the full baseAnnualReturn (Total Return)
  // If includeDividends is FALSE:
  //    If ACCUMULATING: We still use baseAnnualReturn (internal reinvestment is price action)
  //    If DISTRIBUTING: We subtract the dividendYield from baseAnnualReturn (Price Return only)

  let mu1 = etf1.baseAnnualReturn;
  if (!includeDividends && etf1.distribution === DistributionPolicy.DISTRIBUTING) {
      mu1 -= etf1.dividendYield;
  }
  const dailyMu1 = mu1 / 252;
  const dailySigma1 = etf1.volatility / Math.sqrt(252);

  let dailyMu2 = 0;
  let dailySigma2 = 0;

  if (etf2) {
      let mu2 = etf2.baseAnnualReturn;
      if (!includeDividends && etf2.distribution === DistributionPolicy.DISTRIBUTING) {
          mu2 -= etf2.dividendYield;
      }
      dailyMu2 = mu2 / 252;
      dailySigma2 = etf2.volatility / Math.sqrt(252);
  }

  // Generate path
  for (let i = 0; i <= days; i++) {
    const currentDate = new Date(startDate);
    currentDate.setDate(startDate.getDate() + (i * (range === '1M' ? 1 : 1.4))); // approximate calendar spread

    // Random shock component (Box-Muller transform for normal distribution)
    const u1 = Math.random();
    const u2 = Math.random();
    const z1 = Math.sqrt(-2.0 * Math.log(u1)) * Math.cos(2.0 * Math.PI * u2);

    // GBM Formula: S_t = S_{t-1} * exp((mu - 0.5*sigma^2)*dt + sigma*W_t)
    // Simplified for daily: change = val * (mu + sigma * z)

    // We use a fixed seed-like effect by combining day index to keep curve somewhat stable between re-renders if we wanted,
    // but here we let it be random for "simulation" feel or we could fix it. 
    // To make it look real, we just apply the drift and shock.

    const drift1 = dailyMu1 - dailyTer1;
    const shock1 = dailySigma1 * z1;
    val1 = val1 * (1 + drift1 + shock1);

    const point: ChartPoint = {
      date: currentDate.toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: range !== '1M' ? '2-digit' : undefined }),
      etf1Value: Math.round(val1),
    };

    if (etf2) {
        const u3 = Math.random();
        const u4 = Math.random();
        const z2 = Math.sqrt(-2.0 * Math.log(u3)) * Math.cos(2.0 * Math.PI * u4);

        const drift2 = dailyMu2 - dailyTer2;
        const shock2 = dailySigma2 * z2;
        val2 = val2 * (1 + drift2 + shock2);
        point.etf2Value = Math.round(val2);
    }

    data.push(point);
  }

  return data;
};

import React from 'react';
import { 
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, AreaChart, Area 
} from 'recharts';
import { ChartPoint, TimeRange } from '../types';

interface PerformanceChartProps {
  data: ChartPoint[];
  etf1Name: string;
  etf2Name?: string;
  timeRange: TimeRange;
  includeDividends: boolean;
}

export const PerformanceChart: React.FC<PerformanceChartProps> = ({ 
  data, 
  etf1Name, 
  etf2Name, 
  timeRange, 
  includeDividends 
}) => {
  // Calculate percent change for display in tooltip header or similar
  const startVal1 = data[0]?.etf1Value || 1;
  const endVal1 = data[data.length - 1]?.etf1Value || 1;
  const change1 = ((endVal1 - startVal1) / startVal1) * 100;

  return (
    <div className="h-80 w-full bg-white rounded-lg p-2 transition-all">
      <div className="flex justify-between items-center px-4 mb-2">
         <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">
            Simulated Performance ({timeRange}) • {includeDividends ? 'Total Return (Divs Reinvested)' : 'Price Return'}
         </span>
         <span className={`text-xs font-bold ${change1 >= 0 ? 'text-green-600' : 'text-red-600'}`}>
            {etf1Name}: {change1 > 0 ? '+' : ''}{change1.toFixed(2)}%
         </span>
      </div>

      <ResponsiveContainer width="100%" height="90%">
        <AreaChart data={data} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
          <defs>
            <linearGradient id="colorEtf1" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#2563eb" stopOpacity={0.4}/>
              <stop offset="95%" stopColor="#2563eb" stopOpacity={0}/>
            </linearGradient>
            <linearGradient id="colorEtf2" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.4}/>
              <stop offset="95%" stopColor="#f59e0b" stopOpacity={0}/>
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
          <XAxis 
            dataKey="date" 
            tick={{fontSize: 10, fill: '#94a3b8'}} 
            tickLine={false}
            axisLine={false}
            interval={timeRange === '1M' ? 3 : 'preserveStartEnd'}
            minTickGap={30}
          />
          <YAxis 
            domain={['auto', 'auto']}
            tick={{fontSize: 10, fill: '#94a3b8'}} 
            tickLine={false}
            axisLine={false}
            tickFormatter={(value) => `€${(value/1000).toFixed(1)}k`}
            width={40}
          />
          <Tooltip 
            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontSize: '12px' }}
            formatter={(value: number) => [`€${value.toLocaleString()}`, 'Value']}
            labelStyle={{color: '#64748b', marginBottom: '0.25rem'}}
          />
          <Legend wrapperStyle={{fontSize: '12px', paddingTop: '10px'}}/>
          <Area 
            type="monotone" 
            dataKey="etf1Value" 
            name={etf1Name} 
            stroke="#2563eb" 
            fillOpacity={1} 
            fill="url(#colorEtf1)" 
            strokeWidth={2}
            isAnimationActive={false} // Disable animation for instant range switching
          />
          {etf2Name && (
            <Area 
              type="monotone" 
              dataKey="etf2Value" 
              name={etf2Name} 
              stroke="#f59e0b" 
              fillOpacity={1} 
              fill="url(#colorEtf2)" 
              strokeWidth={2}
              isAnimationActive={false}
            />
          )}
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

