import { ETF, TimeRange, ChartPoint, DistributionPolicy } from '../types';
import { getHistoricalDataForEtf } from '../services/etfDataService';

/**
 * AlphaETF Financial Metrics Engine
 * Now uses "Hardcoded Real Data" to simulate external API responses.
 */

const interpolate = (start: number, end: number, factor: number) => {
  return start + (end - start) * factor;
};

export const generateHistoricalData = (
  etf1: ETF,
  etf2: ETF | null,
  range: TimeRange,
  includeDividends: boolean
): ChartPoint[] => {
  // Get base historical curve (Total Return assumption)
  const curve1 = getHistoricalDataForEtf(etf1.ticker);
  const curve2 = etf2 ? getHistoricalDataForEtf(etf2.ticker) : null;

  const data: ChartPoint[] = [];
  const now = new Date();

  // Determine how many months back we go based on range
  let monthsBack = 12;
  if (range === '1M') monthsBack = 1;
  if (range === '1Y') monthsBack = 12;
  if (range === '3Y') monthsBack = 36;
  if (range === '5Y') monthsBack = 60;

  // We have approx 25 points in our static data covering 5 years.
  // We need to upscale this to daily points for the chart.

  const totalCurvePoints = curve1.length;
  // Calculate start index in the static array
  // If array has 25 points (5 years), 1Y is the last 5 points.
  const pointsPerYear = 5; 
  const pointsNeeded = Math.ceil(monthsBack / 12 * pointsPerYear);
  const startIndex = Math.max(0, totalCurvePoints - pointsNeeded - 1);

  const slicedCurve1 = curve1.slice(startIndex);
  const slicedCurve2 = curve2 ? curve2.slice(startIndex) : null;

  // Generate daily points by interpolating between the "Monthly" static points
  const daysTotal = monthsBack === 1 ? 21 : monthsBack * 21; // Approx trading days
  const segmentSize = Math.floor(daysTotal / (slicedCurve1.length - 1));

  // Base normalization value (to start at 0%)
  const startValue1 = slicedCurve1[0];
  const startValue2 = slicedCurve2 ? slicedCurve2[0] : 1;

  let currentSegment = 0;

  for (let i = 0; i < daysTotal; i++) {
    // Determine which two static points we are between
    if (i > (currentSegment + 1) * segmentSize && currentSegment < slicedCurve1.length - 2) {
      currentSegment++;
    }

    const p1_1 = slicedCurve1[currentSegment];
    const p2_1 = slicedCurve1[currentSegment + 1] || p1_1;

    // Progress within the segment (0 to 1)
    const segmentProgress = (i - (currentSegment * segmentSize)) / segmentSize;
    // Add micro-noise for "Daily" look
    const noise = (Math.random() - 0.5) * 0.5;

    let val1 = interpolate(p1_1, p2_1, segmentProgress) + noise;

    // --- DIVIDEND LOGIC ---
    // The base curve is assumed to be Total Return (Index performance).
    // If the ETF is Distributing AND includeDividends is FALSE, we must subtract the yield.
    // If Accumulating, the price tracks the index (Total Return).

    if (etf1.distribution === DistributionPolicy.DISTRIBUTING && !includeDividends) {
        // Linearly subtract yield over time to simulate "Price Return" vs "Total Return" gap
        const yearsPassed = i / 252;
        const drag = val1 * (etf1.dividendYield * yearsPassed);
        val1 -= drag;
    }

    // Normalize to Percentage Change
    const pct1 = ((val1 - startValue1) / startValue1) * 100;

    const date = new Date(now);
    date.setDate(now.getDate() - (daysTotal - i));

    const point: ChartPoint = {
      date: date.toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: range === '5Y' ? '2-digit' : undefined }),
      etf1Value: parseFloat(pct1.toFixed(2)),
    };

    if (slicedCurve2 && etf2) {
        const p1_2 = slicedCurve2[currentSegment];
        const p2_2 = slicedCurve2[currentSegment + 1] || p1_2;
        let val2 = interpolate(p1_2, p2_2, segmentProgress) + noise;

        if (etf2.distribution === DistributionPolicy.DISTRIBUTING && !includeDividends) {
            const yearsPassed = i / 252;
            const drag = val2 * (etf2.dividendYield * yearsPassed);
            val2 -= drag;
        }

        const pct2 = ((val2 - startValue2) / startValue2) * 100;
        point.etf2Value = parseFloat(pct2.toFixed(2));
    }

    data.push(point);
  }

  return data;
};

