/**
 * Returns the raw historical price series adjusted for the selected currency.
 * This simulates a "Real" backend calculating returns based on FX rates.
 */
export const getCurrencyAdjustedSeries = (ticker: string, targetCurrency: string): number[] => {
  const t = ticker.toUpperCase();
  let baseSeries: number[] = [];

  // 1. Identify Base Series (Source Data)
  if (t.includes('S&P') || t === 'SXR8' || t === 'VUSA' || t === 'QDVE') baseSeries = REAL_QUOTES['SP500'];
  else if (t.includes('NASDAQ') || t === 'EQQQ') baseSeries = REAL_QUOTES['NASDAQ'];
  else if (t === 'EMIM') baseSeries = REAL_QUOTES['EM'];
  else if (t === 'AGGH') baseSeries = REAL_QUOTES['BONDS'];
  else baseSeries = REAL_QUOTES['WORLD']; // Default to All-World

  // 2. Identify Source Currency of the Data (Approximation)
  const sourceCurrency = t === 'AGGH' ? 'EUR' : 'USD';

  // 3. Apply FX Conversion
  if (sourceCurrency === targetCurrency) {
    return [...baseSeries];
  }

  // Conversion Logic
  return baseSeries.map((price, index) => {
    // Handling array length mismatches safely (repeating last known rate if needed)
    const safeIndex = Math.min(index, FX_RATES['USD_PLN'].length - 1);

    if (sourceCurrency === 'USD' && targetCurrency === 'PLN') {
      return price * FX_RATES['USD_PLN'][safeIndex];
    }
    if (sourceCurrency === 'USD' && targetCurrency === 'EUR') {
      // USD -> EUR = USD * (USD/PLN) / (EUR/PLN) - Indirect cross rate for consistency in this mock
      const usdPln = FX_RATES['USD_PLN'][safeIndex];
      const eurPln = FX_RATES['EUR_PLN'][safeIndex];
      return price * (usdPln / eurPln); 
    }
    if (sourceCurrency === 'EUR' && targetCurrency === 'PLN') {
      return price * FX_RATES['EUR_PLN'][safeIndex];
    }
    if (sourceCurrency === 'EUR' && targetCurrency === 'USD') {
      const usdPln = FX_RATES['USD_PLN'][safeIndex];
      const eurPln = FX_RATES['EUR_PLN'][safeIndex];
      return price * (eurPln / usdPln);
    }

    return price; // Fallback
  });
};

