import { ETF, TimeRange, ChartPoint, DistributionPolicy } from '../types';
import { getCurrencyAdjustedSeries } from '../services/etfDataService';

/**
 * AlphaETF Financial Metrics Engine - DAILY DATA GENERATOR
 * Uses Brownian Bridge algorithm to generate realistic daily volatility 
 * between known historical monthly anchor points.
 */

// Helper: Brownian Bridge Interpolation
// Generates 'steps' number of points between start and end values with market-like volatility
const generateDailyPath = (startVal: number, endVal: number, steps: number, volatility: number): number[] => {
  const path: number[] = [startVal];
  let current = startVal;

  // Standard deviation for daily moves (approximate)
  const dt = 1 / steps;

  // Pre-calculate random walks
  const randomWalks: number[] = [];
  let sum = 0;
  for (let i = 0; i < steps; i++) {
    const shock = (Math.random() - 0.5) * 2; // -1 to 1
    sum += shock;
    randomWalks.push(sum);
  }

  for (let i = 1; i <= steps; i++) {
    const t = i / steps;

    // Linear interpolation component (Drift)
    const drift = startVal + (endVal - startVal) * t;

    // Brownian Bridge component (Noise that converges to 0 at t=1)
    // We use the pre-calculated random walk but scale it to bridge back to the target
    // Simplified bridge logic for visual consistency:
    const bridgeNoise = (Math.random() - 0.5) * volatility * startVal * 0.02 * (1 - Math.abs(t - 0.5) * 0.5); // Less noise at ends

    // Combine
    path.push(drift + bridgeNoise);
  }

  // Force the last point to match strictly (fixing any rounding/noise drift)
  path[path.length - 1] = endVal;

  return path.slice(1); // Exclude start, as it's the end of previous segment
};

export const generateHistoricalData = (
  etf1: ETF,
  etf2: ETF | null,
  range: TimeRange,
  includeDividends: boolean,
  targetCurrency: string = 'EUR'
): ChartPoint[] => {
  // 1. Get Monthly Anchors (The "Real" Macro Data)
  const anchors1 = getCurrencyAdjustedSeries(etf1.ticker, targetCurrency);
  const anchors2 = etf2 ? getCurrencyAdjustedSeries(etf2.ticker, targetCurrency) : null;

  const data: ChartPoint[] = [];
  const now = new Date();

  // Determine range in trading days (approx)
  let daysBack = 252; // 1Y default
  if (range === '1M') daysBack = 21;
  if (range === '1Y') daysBack = 252;
  if (range === '3Y') daysBack = 756;
  if (range === '5Y') daysBack = 1260;

  // We have ~60 monthly anchors. We need to bridge them to get ~1260 daily points.
  // We work backwards from the most recent data.

  let generatedPoints: { date: Date, v1: number, v2?: number }[] = [];

  // Indexes for anchors
  let anchorIdx = anchors1.length - 1;
  let currentVal1 = anchors1[anchorIdx];
  let currentVal2 = anchors2 ? anchors2[anchorIdx] : 0;

  // We will iterate backwards from Today, generating "months" of daily data
  // until we fill the requested time range.

  // Start with today
  generatedPoints.push({ date: new Date(now), v1: currentVal1, v2: currentVal2 });

  let daysGenerated = 0;

  while (daysGenerated < daysBack && anchorIdx > 0) {
    const targetAnchorIdx = anchorIdx - 1;

    // Values at the START of this month (which is the END of the previous segment in time-forward logic, 
    // but here we are going backwards, so we are looking at the value ~21 days ago)
    const prevMonthVal1 = anchors1[targetAnchorIdx];
    const prevMonthVal2 = anchors2 ? anchors2[targetAnchorIdx] : 0;

    // Detect volatility regime based on the monthly move magnitude
    const movePct = Math.abs((currentVal1 - prevMonthVal1) / prevMonthVal1);
    const volatilityFactor = movePct > 0.10 ? 3.0 : movePct > 0.05 ? 1.5 : 0.8; // High vol if moved >10% in a month

    // Generate ~21 trading days for this month
    const daysInMonth = 21; 

    // We generate FORWARD from Prev -> Current, then reverse to add to our backward list
    const monthPath1 = generateDailyPath(prevMonthVal1, currentVal1, daysInMonth, volatilityFactor);
    const monthPath2 = anchors2 ? generateDailyPath(prevMonthVal2, currentVal2, daysInMonth, volatilityFactor) : [];

    // Add to points in reverse order (newest to oldest)
    for (let i = daysInMonth - 1; i >= 0; i--) {
        const d = new Date(now);
        d.setDate(d.getDate() - (generatedPoints.length)); // Go back 1 day for each existing point

        // Skip weekends for realism
        if (d.getDay() === 0) d.setDate(d.getDate() - 2);
        if (d.getDay() === 6) d.setDate(d.getDate() - 1);

        generatedPoints.push({
            date: d,
            v1: monthPath1[i],
            v2: anchors2 ? monthPath2[i] : undefined
        });
    }

    // Move anchors back
    currentVal1 = prevMonthVal1;
    currentVal2 = prevMonthVal2;
    anchorIdx--;
    daysGenerated += daysInMonth;
  }

  // Reverse entire array to be Chronological (Oldest -> Newest) for the Chart
  generatedPoints = generatedPoints.reverse();

  // Trim to exact requested range if we generated slightly too many
  if (generatedPoints.length > daysBack) {
      generatedPoints = generatedPoints.slice(generatedPoints.length - daysBack);
  }

  // Normalization Base (Start at 0%)
  const startV1 = generatedPoints[0].v1;
  const startV2 = generatedPoints[0].v2 || 1;

  return generatedPoints.map((pt, index) => {
    let v1 = pt.v1;
    let v2 = pt.v2;

    // --- DIVIDEND LOGIC (Applied Daily) ---
    // Calculate drag if "Price Return" (No Dividends) is selected
    if (etf1.distribution === DistributionPolicy.DISTRIBUTING && !includeDividends) {
        const yearsPassed = index / 252;
        v1 = v1 * (1 - (etf1.dividendYield * yearsPassed));
    }

    if (v2 && etf2 && etf2.distribution === DistributionPolicy.DISTRIBUTING && !includeDividends) {
        const yearsPassed = index / 252;
        v2 = v2 * (1 - (etf2.dividendYield * yearsPassed));
    }

    // Convert to Percentage
    const pct1 = ((v1 - startV1) / startV1) * 100;
    const pct2 = v2 ? ((v2 - startV2) / startV2) * 100 : undefined;

    return {
        date: pt.date.toLocaleDateString('en-GB', { 
            day: '2-digit', 
            month: 'short', 
            year: range === '5Y' || range === '3Y' ? '2-digit' : undefined 
        }),
        etf1Value: parseFloat(pct1.toFixed(2)),
        etf2Value: pct2 !== undefined ? parseFloat(pct2.toFixed(2)) : undefined
    };
  });
};

