// Helper: Pseudo-random number generator based on date string
// Returns -0.5 to 0.5. Deterministic (same input = same output).
const getDeterministicNoise = (dateStr: string, seed: number = 1): number => {
    let hash = 0;
    const str = dateStr + seed.toString();
    for (let i = 0; i < str.length; i++) {
        const char = str.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash = hash & hash; // Convert to 32bit integer
    }
    // Normalize to -0.5 to 0.5
    const x = Math.sin(hash) * 10000;
    return x - Math.floor(x) - 0.5;
};

// Helper: Get interpolated value for a specific single date
const getValueAtDate = (date: Date, keyframes: { date: string; val: number }[]): number => {
    const targetTime = date.getTime();

    // Find surrounding keyframes
    let p1 = keyframes[0];
    let p2 = keyframes[keyframes.length - 1];

    for (let i = 0; i < keyframes.length - 1; i++) {
        const t1 = new Date(keyframes[i].date).getTime();
        const t2 = new Date(keyframes[i+1].date).getTime();
        if (targetTime >= t1 && targetTime <= t2) {
            p1 = keyframes[i];
            p2 = keyframes[i+1];
            break;
        }
    }

    const t1 = new Date(p1.date).getTime();
    const t2 = new Date(p2.date).getTime();
    const totalSpan = t2 - t1;
    const currentSpan = targetTime - t1;

    // Linear Progress (0 to 1)
    const progress = totalSpan === 0 ? 0 : currentSpan / totalSpan;

    // Linear Value
    const linearVal = p1.val + (p2.val - p1.val) * progress;

    // Add Deterministic Noise
    // We add more noise if the gap between keyframes is large (implied volatility)
    const noise = getDeterministicNoise(date.toISOString().split('T')[0], p1.val) * (p1.val * 0.02); // 2% daily variance max

    return linearVal + noise;
};

