/**
 * Returns a daily price series for a specific ticker over a specific date range.
 * Calculates FX on the fly deterministically.
 */
export const getDeterministicHistory = (
    ticker: string, 
    targetCurrency: string,
    daysBack: number
): { date: string; value: number }[] => {

    // 1. Identify Source Data
    const t = ticker.toUpperCase();
    let historyKey = 'WORLD'; // Default
    if (t.includes('S&P') || t === 'SXR8' || t === 'VUSA' || t === 'QDVE') historyKey = 'SP500';
    else if (t.includes('NASDAQ') || t === 'EQQQ') historyKey = 'NASDAQ';
    else if (t === 'AGGH') historyKey = 'BONDS';

    const sourceData = MARKET_HISTORY[historyKey];
    const sourceCurrency = historyKey === 'BONDS' ? 'EUR' : 'USD';

    // 2. Generate Daily Points
    const result: { date: string; value: number }[] = [];
    const now = new Date();

    // Create array of dates backwards
    for (let i = 0; i < daysBack; i++) {
        const d = new Date(now);
        d.setDate(d.getDate() - (daysBack - 1 - i)); // Chronological order

        // Skip weekends? Let's keep it simple and just generate all, 
        // chart libraries handle weekends fine usually, or we can filter.
        // For realism, let's skip weekends.
        if (d.getDay() === 0 || d.getDay() === 6) continue;

        // Get Base Price
        let price = getValueAtDate(d, sourceData);

        // Apply FX
        if (sourceCurrency !== targetCurrency) {
            let fxRate = 1;
            if (sourceCurrency === 'USD' && targetCurrency === 'PLN') {
                fxRate = getValueAtDate(d, MARKET_HISTORY['USD_PLN']);
            } else if (sourceCurrency === 'EUR' && targetCurrency === 'PLN') {
                fxRate = getValueAtDate(d, MARKET_HISTORY['EUR_PLN']);
            } else if (sourceCurrency === 'USD' && targetCurrency === 'EUR') {
                const usdPln = getValueAtDate(d, MARKET_HISTORY['USD_PLN']);
                const eurPln = getValueAtDate(d, MARKET_HISTORY['EUR_PLN']);
                fxRate = usdPln / eurPln;
            }
            price = price * fxRate;
        }

        result.push({
            date: d.toISOString().split('T')[0],
            value: price
        });
    }

    return result;
};


