import { ETF, TimeRange, ChartPoint, DistributionPolicy } from '../types';
import { getDeterministicHistory } from '../services/etfDataService';

/**
 * AlphaETF Financial Metrics Engine - STABLE VERSION
 * Fetches deterministic daily data and applies dividend adjustments.
 * No Math.random() is used here.
 */

export const generateHistoricalData = (
  etf1: ETF,
  etf2: ETF | null,
  range: TimeRange,
  includeDividends: boolean,
  targetCurrency: string = 'EUR'
): ChartPoint[] => {

  // 1. Determine exact days count for calendar accuracy
  let daysBack = 365;
  if (range === '1M') daysBack = 31;
  if (range === '1Y') daysBack = 365;
  if (range === '3Y') daysBack = 365 * 3;
  if (range === '5Y') daysBack = 365 * 5; // Approx

  // 2. Fetch Deterministic Series (Source of Truth)
  // This will return the exact same array for the same inputs every time.
  const series1 = getDeterministicHistory(etf1.ticker, targetCurrency, daysBack);
  const series2 = etf2 ? getDeterministicHistory(etf2.ticker, targetCurrency, daysBack) : null;

  if (series1.length === 0) return [];

  // 3. Normalize and Apply Dividends
  // We normalize everything to 0% start based on the first available point in the requested range.
  const startVal1 = series1[0].value;
  const startVal2 = series2 ? series2[0].value : 1;

  return series1.map((pt, index) => {
    let v1 = pt.value;

    // Dividend Logic (Simplistic Drag Model)
    // If it's a Distributing ETF and user unchecked "Include Dividends", we simulate price drop (drag).
    if (etf1.distribution === DistributionPolicy.DISTRIBUTING && !includeDividends) {
        // Linear drag approximation: Yield / 252 trading days roughly
        const yearsPassed = index / 252; // Approximate trading days per year
        v1 = v1 * (1 - (etf1.dividendYield * yearsPassed));
    }

    // Calculate Percentage Change
    const pct1 = ((v1 - startVal1) / startVal1) * 100;

    const chartPt: ChartPoint = {
        date: new Date(pt.date).toLocaleDateString('en-GB', { 
            day: '2-digit', 
            month: 'short', 
            year: range === '5Y' || range === '3Y' ? '2-digit' : undefined 
        }),
        etf1Value: parseFloat(pct1.toFixed(2))
    };

    if (series2 && etf2) {
        // Match dates roughly (assuming series lengths match due to same daysBack)
        const pt2 = series2[index] || series2[series2.length - 1];
        let v2 = pt2.value;

        if (etf2.distribution === DistributionPolicy.DISTRIBUTING && !includeDividends) {
            const yearsPassed = index / 252;
            v2 = v2 * (1 - (etf2.dividendYield * yearsPassed));
        }

        const pct2 = ((v2 - startVal2) / startVal2) * 100;
        chartPt.etf2Value = parseFloat(pct2.toFixed(2));
    }

    return chartPt;
  });
};

