/**
 * GEMINI FINANCIAL DATA BRIDGE
 * 
 * This service treats the Gemini LLM as a historical financial database.
 * It requests structured JSON data for ETF closing prices over specific periods.
 */

// Initialize client
const getClient = () => {
    return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
}

// Simple in-memory cache to prevent re-fetching the same data repeatedly during a session
const CACHE: Record<string, { date: string; close: number }[]> = {};

export const getEtfs = async (): Promise<ETF[]> => {
    // Keeping the mock list of ETFs as the "Universe" definition, 
    // but their performance data will now come from the AI.
