    });
};

/**
 * Fetches historical monthly closing prices via Gemini.
 * We ask for monthly data to ensure accuracy and fit within context limits,
 * then interpolate daily views in the UI.
 */
export const getGeminiHistory = async (
    ticker: string, 
    currency: string, 
    years: number
): Promise<{ date: string; close: number }[]> => {

    // Create a cache key
    const cacheKey = `${ticker}-${currency}-${years}`;
    if (CACHE[cacheKey]) {
        console.log(`Using cached data for ${cacheKey}`);
        return CACHE[cacheKey];
    }

    const client = getClient();
    const endDate = new Date().toISOString().split('T')[0];
    const startDateObj = new Date();
    startDateObj.setFullYear(startDateObj.getFullYear() - years);
    const startDate = startDateObj.toISOString().split('T')[0];

    // Strict prompt to act as a Data API
    const prompt = `
        You are a strict Financial Data API. 
        Return a JSON array of MONTHLY closing prices for the ETF ticker "${ticker}" denominated in "${currency}".
        Time Range: From ${startDate} to ${endDate}.

        Rules:
        1. Return ONLY raw JSON. No markdown formatting, no code blocks, no intro text.
        2. The JSON must be an array of objects with strict keys: "date" (YYYY-MM-DD format) and "close" (number).
        3. Ensure the data reflects real historical market trends (e.g. 2020 crash, 2022 bear market) as accurately as possible from your training data.
        4. If the exact ticker is obscure, use the closest major index it tracks (e.g. S&P 500 for SXR8, FTSE All-World for VWCE) but adjusted for the requested currency.
    `;

    try {
        const response = await client.models.generateContent({
            model: 'gemini-3-flash-preview', // Using Flash for speed/throughput
            contents: prompt,
            config: {
                responseMimeType: 'application/json'
            }
        });

        const text = response.text;
        if (!text) throw new Error("Empty response from AI");

        // Parse JSON
        const data = JSON.parse(text);

        // Validate structure briefly
        if (!Array.isArray(data)) throw new Error("AI did not return an array");

        // Save to cache
        CACHE[cacheKey] = data;

        return data;

    } catch (error) {
        console.error("Failed to fetch history from Gemini:", error);
        // Fallback: Return an empty array or a flat line to indicate error visually without crashing
        return [];
    }
};

