/**
 * GEMINI FINANCIAL DATA BRIDGE
 * 
 * This service treats the Gemini LLM as a historical financial database.
 * It requests structured JSON data for ETF closing prices over specific periods.
 */

// Initialize client
const getClient = () => {
    return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
}

// Simple in-memory cache to prevent re-fetching the same data repeatedly during a session
const CACHE: Record<string, { date: string; close: number }[]> = {};

export const getEtfs = async (): Promise<ETF[]> => {
    // Keeping the mock list of ETFs as the "Universe" definition, 
    // but their performance data will now come from the AI.
    return new Promise((resolve) => {
        setTimeout(() => resolve(MOCK_ETFS), 100);
    });
};

/**
 * Fetches historical WEEKLY Adjusted Closing prices via Gemini.
 * We switched to Weekly to increase granularity (accuracy) while staying within reliable token limits.
 */
export const getGeminiHistory = async (
    ticker: string, 
    currency: string, 
    years: number
): Promise<{ date: string; close: number }[]> => {

    // Create a cache key
    const cacheKey = `${ticker}-${currency}-${years}-weekly`;
    if (CACHE[cacheKey]) {
        console.log(`Using cached data for ${cacheKey}`);
        return CACHE[cacheKey];
    }

    const client = getClient();
    const today = new Date();
    // Format Date YYYY-MM-DD
    const endDate = today.toISOString().split('T')[0]; 

    const startDateObj = new Date();
    startDateObj.setFullYear(startDateObj.getFullYear() - years);
    const startDate = startDateObj.toISOString().split('T')[0];

    // Strict prompt to act as a Data API
    const prompt = `
        You are a High-Precision Financial Data Engine.
        Task: Provide historical price data for ETF "${ticker}" in currency "${currency}".

        Parameters:
        - Start Date: ${startDate}
        - End Date: ${endDate} (Today/Latest Close)
        - Frequency: **WEEKLY** (Every Friday close)
        - Data Type: **ADJUSTED CLOSE** (Total Return). You MUST account for dividends and splits. 

        Reference Sources: Mimic data from Stooq, Yahoo Finance, or Bloomberg.

        Output Requirements:
        1. Return ONLY a raw JSON array.
        2. Format: [{"date": "YYYY-MM-DD", "close": 123.45}, ...]
        3. CRITICAL: The last data point must be the exact closing price from the most recent trading session (${endDate} or yesterday).
        4. CRITICAL: The first data point must match the price on or near ${startDate}.
        5. Do not hallucinate trends. Use your internal knowledge base to retrieve the actual historical volatility and price levels for this specific ticker.
    `;

    try {
        const response = await client.models.generateContent({
            model: 'gemini-3-flash-preview', // Flash is fast and capable of data retrieval
            contents: prompt,
            config: {
                responseMimeType: 'application/json',
                temperature: 0.1 // Low temperature for factual consistency
            }
        });

        const text = response.text;
        if (!text) throw new Error("Empty response from AI");

        // Parse JSON
        const data = JSON.parse(text);

        // Validate structure briefly
        if (!Array.isArray(data)) throw new Error("AI did not return an array");

        // Save to cache
        CACHE[cacheKey] = data;

        return data;

    } catch (error) {
        console.error("Failed to fetch history from Gemini:", error);
        return [];
    }
};

