/**
 * GEMINI FINANCIAL DATA BRIDGE
 * 
 * This service treats the Gemini LLM as a historical financial database.
 * It requests structured JSON data for ETF closing prices over specific periods.
 */

// Initialize client
const getClient = () => {
    return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
}

export interface HistoryResponse {
    data: { date: string; close: number }[];
    sources: string[];
}

// Simple in-memory cache
const CACHE: Record<string, HistoryResponse> = {};

