    });
};

/**
 * Fetches historical WEEKLY Adjusted Closing prices via Gemini.
 * USES GOOGLE SEARCH to ensure data is real and up-to-date.
 */
export const getGeminiHistory = async (
    ticker: string, 
    currency: string, 
    years: number
): Promise<HistoryResponse> => {

    // Create a cache key
    const cacheKey = `${ticker}-${currency}-${years}-search`;
    if (CACHE[cacheKey]) {
        console.log(`Using cached data for ${cacheKey}`);
        return CACHE[cacheKey];
    }

    const client = getClient();
    const today = new Date();
    const endDate = today.toISOString().split('T')[0]; 

    const startDateObj = new Date();
    startDateObj.setFullYear(startDateObj.getFullYear() - years);
    // Add a small buffer to ensure we cover the start of the chart
    startDateObj.setDate(startDateObj.getDate() - 7); 
    const startDate = startDateObj.toISOString().split('T')[0];

    // Strict prompt with Search Grounding
    const prompt = `
        You are a Real-Time Financial Data Retrieval Agent.

        OBJECTIVE: Retrieve ACTUAL historical price data for the ETF "${ticker}" expressed in "${currency}".
        DATE RANGE: ${startDate} to ${endDate}.
        INTERVAL: Weekly (End of week close).

        INSTRUCTIONS:
        1. USE GOOGLE SEARCH to find historical data tables from sources like Stooq, Yahoo Finance, Investing.com, or AtlasETF.
        2. SEARCH QUERY SUGGESTION: "historical data ${ticker} ${currency} stooq" or "${ticker} ETF price history ${currency}".
        3. CURRENCY HANDLING: 
           - If the ETF trades in USD/EUR but the user wants ${currency} (and they are different), you MUST search for the historical FX rates (${ticker}'s base currency to ${currency}) and convert the prices yourself, OR search for the specific listing on a local exchange (e.g. GPW) if it exists.
        4. ACCURACY: The data must match reality. Do not simulate. Copy the values you find. The last point must be the latest available close (yesterday/today).

        OUTPUT FORMAT:
        Return ONLY a JSON array of objects. No markdown formatting.
        Example: [{"date": "2024-01-05", "close": 115.20}, {"date": "2024-01-12", "close": 114.80}, ...]
    `;

    try {
        const response = await client.models.generateContent({
            model: 'gemini-3-flash-preview', 
            contents: prompt,
            config: {
                // Enable Search Tool
                tools: [{ googleSearch: {} }],
                responseMimeType: 'application/json',
                temperature: 0.1
            }
        });

        const text = response.text;
        if (!text) throw new Error("Empty response from AI");

        // Parse JSON
        const data = JSON.parse(text);

        // Extract Sources from Grounding Metadata
        const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
            ?.map((chunk: any) => chunk.web?.uri)
            .filter((uri: string) => !!uri) as string[] || [];

        // Validate structure
        if (!Array.isArray(data)) throw new Error("AI did not return an array");

        const result = { data, sources: [...new Set(sources)] }; // Unique sources

        // Save to cache
        CACHE[cacheKey] = result;

        return result;

    } catch (error) {
        console.error("Failed to fetch history from Gemini:", error);
        return { data: [], sources: [] };
    }
};

