// Helper component for Market Status
const MarketIndicator: React.FC<{ name: string; timezone: string; openHour: number; closeHour: number }> = ({ name, timezone, openHour, closeHour }) => {
  const [isOpen, setIsOpen] = useState(false);
  useEffect(() => {
    const checkStatus = () => {
      const now = new Date();
      const marketTime = new Date(now.toLocaleString("en-US", { timeZone: timezone }));
      const currentFloat = marketTime.getHours() + marketTime.getMinutes() / 60;
      const day = marketTime.getDay();
      setIsOpen(day !== 0 && day !== 6 && currentFloat >= openHour && currentFloat < closeHour);
    };
    checkStatus();
    const interval = setInterval(checkStatus, 60000);
    return () => clearInterval(interval);
  }, [timezone, openHour, closeHour]);
  return (
    <div className="flex justify-between items-center py-1">
      <span className="text-slate-400">{name}</span>
      <span className={`text-xs font-bold px-2 py-0.5 rounded ${isOpen ? 'bg-green-500/10 text-green-400' : 'bg-red-500/10 text-red-400'}`}>
        {isOpen ? 'Open' : 'Closed'}
      </span>
    </div>
  );
};

const App: React.FC = () => {
  // Global State
  const [currency, setCurrency] = useState<string>('PLN'); // Default to PLN based on feedback
  const [taxDomicile, setTaxDomicile] = useState<string>('Poland');

  // Selection State
  const [etfLeft, setEtfLeft] = useState<ETF | null>(null);
  const [etfRight, setEtfRight] = useState<ETF | null>(null);
  const [activeCategory, setActiveCategory] = useState<EtfCategory>('Global');

  // Data State
  const [allEtfs, setAllEtfs] = useState<ETF[]>([]);
  const [loading, setLoading] = useState(true);

  // Analysis & Chart State
  const [aiAnalysis, setAiAnalysis] = useState<string>('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [timeRange, setTimeRange] = useState<TimeRange>('1Y');
  const [includeDividends, setIncludeDividends] = useState<boolean>(true);
  const [chartData, setChartData] = useState<ChartPoint[]>([]);
  const [chartSources, setChartSources] = useState<string[]>([]);
  const [isChartLoading, setIsChartLoading] = useState(false);

  // Load Data
  useEffect(() => {
    getEtfs().then(data => {
      setAllEtfs(data);
      setLoading(false);
    });
  }, []);

  // Filtered List based on Tab
  const displayedEtfs = useMemo(() => {
      return allEtfs.filter(e => e.category === activeCategory);
  }, [allEtfs, activeCategory]);

  const categories: EtfCategory[] = ['Global', 'USA S&P500', 'Tech/Nasdaq', 'Europe', 'Emerging', 'Bonds/Special'];

  // Handlers
  const handleSelectLeft = (etf: ETF) => {
      setEtfLeft(etf);
      if (etfRight?.isin === etf.isin) setEtfRight(null); // Prevent same on both sides
      setAiAnalysis('');
  };
  const handleSelectRight = (etf: ETF) => {
      setEtfRight(etf);
      if (etfLeft?.isin === etf.isin) setEtfLeft(null);
      setAiAnalysis('');
  };

  const runAnalysis = async () => {
    if (!etfLeft || !etfRight) return;
    setIsAnalyzing(true);
    const result = await analyzeEtfComparison(etfLeft, etfRight);
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  const commonBrokers = useMemo(() => {
      const selected = [etfLeft, etfRight].filter(Boolean) as ETF[];
      if (selected.length === 0) return [];
      return getBrokersForEtfs(selected);
  }, [etfLeft, etfRight]);

  // Chart Data Effect
  useEffect(() => {
    const fetchData = async () => {
        if (!etfLeft && !etfRight) {
            setChartData([]);
            setChartSources([]);
            return;
        }

        setIsChartLoading(true);

        let years = 1;
        if (timeRange === '1M') years = 0.1;
        if (timeRange === '3Y') years = 3;
        if (timeRange === '5Y') years = 5;

        try {
            const fetch1 = etfLeft ? getGeminiHistory(etfLeft.ticker, currency, years) : Promise.resolve(null);
            const fetch2 = etfRight ? getGeminiHistory(etfRight.ticker, currency, years) : Promise.resolve(null);

            const [resp1, resp2] = await Promise.all([fetch1, fetch2]);

            const allSources = new Set<string>();
            if (resp1) resp1.sources.forEach(s => allSources.add(s));
            if (resp2) resp2.sources.forEach(s => allSources.add(s));
            setChartSources(Array.from(allSources));

            const processed = processChartData(
                etfLeft || {} as any, 
                resp1 ? resp1.data : [], 
                etfRight || null, 
                resp2 ? resp2.data : null, 
                includeDividends
            );
            setChartData(processed);

        } catch (err) {
            console.error("Error fetching chart data", err);
        } finally {
            setIsChartLoading(false);
        }
    };

    fetchData();
  }, [etfLeft, etfRight, timeRange, currency, includeDividends]);

  return (
    <div className="min-h-screen flex flex-col xl:flex-row bg-slate-50 text-slate-800 font-sans">

      {/* Sidebar Navigation */}
      <aside className="w-full xl:w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col justify-between">
        <div>
          <div className="p-6">
            <h1 className="text-2xl font-bold tracking-tight bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent">
              AlphaETF
            </h1>
            <p className="text-slate-400 text-sm mt-1">AI Investment Co-Pilot</p>
          </div>

          <div className="px-6 py-4">
              <div className="mb-4">
                <label className="text-[10px] font-semibold text-slate-500 uppercase block mb-2">My Domicile</label>
                <select value={taxDomicile} onChange={(e) => setTaxDomicile(e.target.value)} className="w-full bg-slate-800 text-sm rounded px-3 py-2 border border-slate-700 outline-none">
                    <option value="Poland">Poland</option>
                    <option value="Germany">Germany</option>
                    <option value="UK">UK</option>
                </select>
              </div>
              <div>
                <label className="text-[10px] font-semibold text-slate-500 uppercase block mb-2">Display Currency</label>
                <select value={currency} onChange={(e) => setCurrency(e.target.value)} className="w-full bg-slate-800 text-sm rounded px-3 py-2 border border-slate-700 outline-none">
                    <option value="PLN">PLN (zł)</option>
                    <option value="EUR">EUR (€)</option>
                    <option value="USD">USD ($)</option>
                </select>
              </div>
          </div>
        </div>

        <div className="p-6 border-t border-slate-800">
            <MarketIndicator name="GPW (Warsaw)" timezone="Europe/Warsaw" openHour={9} closeHour={17.08} />
            <MarketIndicator name="Xetra (DE)" timezone="Europe/Berlin" openHour={9} closeHour={17.5} />
            <MarketIndicator name="NYSE (US)" timezone="America/New_York" openHour={9.5} closeHour={16} />
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8">

        {/* Comparator Header - The "Split View" */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
            {/* Slot A */}
            {etfLeft ? (
                <SelectedSlot 
                    etf={etfLeft} 
                    label="Asset A" 
                    color="bg-blue-500" 
                    onRemove={() => setEtfLeft(null)} 
                />
            ) : (
                <EmptySlot label="Asset A" colorClass="hover:border-blue-400 hover:bg-blue-50" />
            )}

            {/* Slot B */}
            {etfRight ? (
                <SelectedSlot 
                    etf={etfRight} 
                    label="Asset B" 
                    color="bg-amber-500" 
                    onRemove={() => setEtfRight(null)} 
                />
            ) : (
                <EmptySlot label="Asset B" colorClass="hover:border-amber-400 hover:bg-amber-50" />
            )}
        </div>

        {/* Charts Section (Only if at least one selected) */}
        {(etfLeft || etfRight) && (
             <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 mb-8 animate-in fade-in duration-500">
                <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4">
                    <h3 className="text-lg font-bold text-slate-800">Total Return ({currency})</h3>
                    <div className="flex items-center gap-3">
                         <div className="flex bg-slate-100 p-1 rounded-lg">
                            {(['1M', '1Y', '3Y', '5Y'] as TimeRange[]).map(r => (
                                <button key={r} onClick={() => setTimeRange(r)} className={`px-3 py-1 text-xs font-semibold rounded-md ${timeRange === r ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}>{r}</button>
                            ))}
                        </div>
                    </div>
                </div>

                <div className="h-[320px] relative w-full">
                    {isChartLoading && (
                        <div className="absolute inset-0 bg-white/90 z-10 flex flex-col items-center justify-center text-blue-600">
                            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mb-2"></div>
                            <span className="text-xs font-semibold">Scanning Stooq & Yahoo...</span>
                        </div>
                    )}
                    <PerformanceChart 
                        data={chartData} 
                        etf1Name={etfLeft?.ticker || ''} 
                        etf2Name={etfRight?.ticker} 
                        timeRange={timeRange} 
                        includeDividends={true}
                    />
                </div>

                {chartSources.length > 0 && (
                   <div className="mt-2 text-[10px] text-slate-400 flex flex-wrap gap-2">
                       <span>Verified Sources:</span>
                       {chartSources.slice(0, 4).map((s, i) => <a key={i} href={s} target="_blank" className="text-blue-500 hover:underline truncate max-w-[150px]">{new URL(s).hostname}</a>)}
                   </div>
                )}
             </div>
        )}

        {/* Analysis Section */}
        {etfLeft && etfRight && (
             <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-8">
                 <div className="lg:col-span-2">
                    {/* Broker Table */}
                    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                        <div className="px-6 py-4 border-b border-slate-100 bg-slate-50">
                            <h3 className="font-bold text-slate-800">Best Brokers for Selected Pair</h3>
                        </div>
                        <table className="w-full text-sm text-left">
