                                <tr>
                                    <th className="px-6 py-3">Broker</th>
                                    <th className="px-6 py-3">{etfLeft.ticker}</th>
                                    <th className="px-6 py-3">{etfRight.ticker}</th>
                                    <th className="px-6 py-3">FX Fee</th>
