                                <p className="opacity-60 text-center mt-10">Compare two ETFs to generate a professional investment verdict.</p>
                             )}
                        </div>
                        <button onClick={runAnalysis} disabled={isAnalyzing} className="w-full py-3 bg-indigo-500 hover:bg-indigo-400 rounded-lg font-bold shadow-lg transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed">
                            {isAnalyzing ? 'Processing...' : 'Generate Verdict'}
                        </button>
                     </div>
                 </div>
             </div>
        )}

        {/* ETF Universe Selector */}
        <div className="mt-4">
             <div className="flex overflow-x-auto pb-4 gap-2 mb-2 no-scrollbar">
                {categories.map(cat => (
                    <CategoryTab 
                        key={cat} 
                        label={cat} 
                        isActive={activeCategory === cat} 
                        onClick={() => setActiveCategory(cat)} 
                    />
                ))}
             </div>

             {loading ? (
                 <div className="h-40 flex items-center justify-center text-slate-400">Loading Universe...</div>
             ) : (
                 <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 pb-20">
                     {displayedEtfs.map(etf => (
                         <ETFCard 
