                        <table className="w-full text-sm text-left">
                            <thead className="text-xs text-slate-500 uppercase bg-white">
                                <tr>
                                    <th className="px-6 py-3">Broker</th>
                                    <th className="px-6 py-3">{etfLeft.ticker}</th>
                                    <th className="px-6 py-3">{etfRight.ticker}</th>
                                    <th className="px-6 py-3">FX Fee</th>
                                </tr>
                            </thead>
                            <tbody>
                                {commonBrokers.map(b => (
                                    <tr key={b.id} className="border-b border-slate-50 last:border-0 hover:bg-slate-50">
                                        <td className="px-6 py-3 font-medium">{b.name}</td>
                                        <td className="px-6 py-3"><span className="bg-slate-100 text-slate-700 px-2 py-1 rounded text-xs font-bold">{b.etfStatus.find(s => s.isin === etfLeft.isin)?.costNote}</span></td>
                                        <td className="px-6 py-3"><span className="bg-slate-100 text-slate-700 px-2 py-1 rounded text-xs font-bold">{b.etfStatus.find(s => s.isin === etfRight.isin)?.costNote}</span></td>
                                        <td className="px-6 py-3 text-slate-500">{b.currencyConversionFee}%</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                 </div>

                 <div className="lg:col-span-1">
                     <div className="bg-indigo-900 rounded-xl shadow-lg p-6 text-white h-full flex flex-col relative overflow-hidden">
                        <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500 rounded-full blur-3xl opacity-20 -mr-10 -mt-10"></div>
                        <h3 className="font-bold text-xl mb-4 relative z-10 flex items-center gap-2">
                            <svg className="w-5 h-5 text-indigo-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                            AI Verdict
                        </h3>
                        <div className="flex-1 overflow-y-auto text-indigo-100 text-sm leading-relaxed custom-scrollbar mb-4 min-h-[200px]">
                             {isAnalyzing ? (
                                 <div className="flex flex-col items-center justify-center h-full gap-3">
                                     <div className="animate-spin rounded-full h-6 w-6 border-2 border-indigo-400 border-t-transparent"></div>
                                     <span className="text-indigo-300 animate-pulse">Analyzing structures...</span>
                                 </div>
                             ) : aiAnalysis ? (
                                <div className="prose prose-invert prose-sm">
                                    <ReactMarkdown>{aiAnalysis}</ReactMarkdown>
                                </div>
                             ) : (
                                <p className="opacity-60 text-center mt-10">Compare two ETFs to generate a professional investment verdict.</p>
                             )}
                        </div>
                        <button onClick={runAnalysis} disabled={isAnalyzing} className="w-full py-3 bg-indigo-500 hover:bg-indigo-400 rounded-lg font-bold shadow-lg transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed">
                            {isAnalyzing ? 'Processing...' : 'Generate Verdict'}
                        </button>
                     </div>
                 </div>
             </div>
        )}

        {/* ETF Universe Selector */}
        <div className="mt-4">
             <div className="flex overflow-x-auto pb-4 gap-2 mb-2 no-scrollbar">
                {categories.map(cat => (
                    <CategoryTab 
                        key={cat} 
                        label={cat} 
                        isActive={activeCategory === cat} 
                        onClick={() => setActiveCategory(cat)} 
                    />
                ))}
             </div>

             {loading ? (
                 <div className="h-40 flex items-center justify-center text-slate-400">Loading Universe...</div>
             ) : (
                 <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 pb-20">
                     {displayedEtfs.map(etf => (
                         <ETFCard 
                            key={etf.isin} 
                            etf={etf} 
                            isLeftSelected={etfLeft?.isin === etf.isin}
                            isRightSelected={etfRight?.isin === etf.isin}
                            onSelectLeft={handleSelectLeft}
                            onSelectRight={handleSelectRight}
                         />
                     ))}
                 </div>
             )}
        </div>

      </main>
    </div>
  );
};

export default App;

