import { Broker, ETF } from '../types';

/**
 * Broker Mapper Module
 * Implements a simplified Strategy Pattern to determine broker availability and fees
 * based on ETF domicile and specific broker rules (e.g., XTB, mBank, Bossa).
 */

export interface BrokerComparison extends Omit<Broker, 'isAvailable' | 'notes'> {
  etfStatus: {
    isin: string;
    isAvailable: boolean;
    costNote: string;
  }[];
}

const BROKERS_BASE = [
  {
    id: 'xtb',
    name: 'XTB',
    country: 'Poland',
    commissionType: 'Zero',
    commissionRate: 0,
    minCommission: 0,
    currencyConversionFee: 0.5,
  },
  {
    id: 'mbank',
    name: 'mBank (eMakler)',
    country: 'Poland',
    commissionType: 'Variable',
    commissionRate: 0.29,
    minCommission: 1.15, // ~5 PLN converted to EUR for standardized display
    currencyConversionFee: 0.1,
  },
  {
    id: 'bossa',
    name: 'BOŚ (Bossa)',
    country: 'Poland',
    commissionType: 'Variable',
    commissionRate: 0.29,
    minCommission: 1.15,
    currencyConversionFee: 0.1, 
  },
  {
    id: 'degiro',
    name: 'Degiro',
    country: 'Netherlands',
    commissionType: 'Fixed',
    commissionRate: 0,
    minCommission: 1, 
    currencyConversionFee: 0.25,
  },
  {
    id: 'ibkr',
    name: 'Interactive Brokers',
    country: 'USA/Ireland',
    commissionType: 'Variable',
    commissionRate: 0.05,
    minCommission: 1.25,
    currencyConversionFee: 0.002,
  }
];

export const getBrokersForEtfs = (etfs: ETF[]): BrokerComparison[] => {
  return BROKERS_BASE.map(broker => {
    const etfStatus = etfs.map(etf => {
        let isAvailable = true;
        let costNote = `${broker.commissionType === 'Zero' ? 'Free' : broker.commissionRate + '%'}`;

        // REALISTIC AVAILABILITY LOGIC
        // European Brokers (XTB, mBank, etc.) cannot sell US-Domiciled ETFs to retail clients due to PRIIPs/KID regulations.
        // US Domiciled ETFs have ISINs starting with 'US'.
        // UCITS ETFs (IE, LU, DE, FR) are generally available.

        const isUSDomiciled = etf.isin.startsWith('US');
        const isEUBroker = ['xtb', 'mbank', 'bossa', 'degiro'].includes(broker.id);

        if (isUSDomiciled && isEUBroker) {
            isAvailable = false;
            costNote = 'Restricted (No KID)';
        }

        // --- Broker Specific Promo Logic ---

        // mBank often has promos for specific issuers or 0% commission for foreign markets occasionally
        if (broker.id === 'mbank') {
             // Example promo logic (simplified)
             if (etf.issuer === 'Amundi' || etf.issuer === 'Beta') {
                 // costNote = 'Promo: 0%'; // Uncomment if active promo
             }
        }

        // Degiro Core Selection (Free once a month)
        // Common popular tickers in Core Selection (checking roughly)
        if (broker.id === 'degiro') {
            const coreTickers = ['VWCE', 'IWDA', 'SXR8', 'QDVE', 'EMIM'];
            if (coreTickers.includes(etf.ticker)) {
                costNote = 'Core (Free)';
            }
        }

        // XTB is generally 0% commission for turnover < 100k EUR/month
        if (broker.id === 'xtb' && isAvailable) {
            costNote = 'Free <100k€';
        }

        return {
            isin: etf.isin,
            isAvailable,
            costNote
        };
    });

    return {
      ...broker,
      commissionType: broker.commissionType as any,
      etfStatus
    };
