 * GEMINI FINANCIAL DATA BRIDGE
 */

const getClient = () => {
    return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
}

export interface HistoryResponse {
    data: { date: string; close: number }[];
    sources: string[];
}

const CACHE: Record<string, HistoryResponse> = {};

export const getEtfs = async (): Promise<ETF[]> => {
    return new Promise((resolve) => {
        setTimeout(() => resolve(FULL_ETF_UNIVERSE), 50);
    });
};

/**
 * Helper to safely parse JSON from LLM response
 */
const parseGeminiJson = (text: string): any => {
    try {
        // 1. Try direct parse
        return JSON.parse(text);
    } catch (e) {
        // 2. Try stripping markdown code blocks
        try {
            const cleaned = text.replace(/```json\s*|\s*```/g, '').trim();
            return JSON.parse(cleaned);
        } catch (e2) {
            // 3. Try finding the first '[' and last ']'
            try {
                const firstBracket = text.indexOf('[');
                const lastBracket = text.lastIndexOf(']');
                if (firstBracket !== -1 && lastBracket !== -1) {
                    const sub = text.substring(firstBracket, lastBracket + 1);
                    return JSON.parse(sub);
                }
            } catch (e3) {
                // Give up
                return null;
            }
        }
    }
    return null;
};

/**
 * Fetches historical MONTHLY Adjusted Closing prices.
 * We use MONTHLY points to ensure the LLM doesn't hallucinate due to context overload,
 * but we demand extreme precision for those points from verified sources.
 */
export const getGeminiHistory = async (
    ticker: string, 
    currency: string, 
    years: number
): Promise<HistoryResponse> => {

    const cacheKey = `${ticker}-${currency}-${years}-monthly-v3`;
    if (CACHE[cacheKey]) {
        return CACHE[cacheKey];
    }

    const client = getClient();
    const today = new Date();
    const endDate = today.toISOString().split('T')[0]; 

    const startDateObj = new Date();
    startDateObj.setFullYear(startDateObj.getFullYear() - years);
    startDateObj.setDate(startDateObj.getDate() - 15); // Buffer
    const startDate = startDateObj.toISOString().split('T')[0];

    const prompt = `
        You are a Precision Financial Data Agent.

        TASK: Retrieve historical pricing for ETF "${ticker}" in "${currency}".
        RANGE: ${startDate} to ${endDate}.
        DATA POINTS: **End of Month** closing prices + **Today's** price.

        CRITICAL RULES FOR ACCURACY:
        1. **SOURCE OF TRUTH**: Use Google Search to find "Historical Data" tables on Stooq.com (e.g., "${ticker} stooq historical"), Yahoo Finance, or JustETF.
        2. **DATA TYPE**: You MUST retrieve **ADJUSTED CLOSE** (Cena Skorygowana). This is vital. If you grab simple "Close", the chart will drop falsely on dividend days.
        3. **CURRENCY**: If the found data is in USD/EUR but user wants ${currency}, verify the approximate exchange rate for that month and convert. Prefer finding the listing on a local exchange (e.g. GPW for PLN) if available (e.g., VUSA.PL, BETAETF).
        4. **VERIFICATION**: Look at the chart on the source website. If the price dropped 20% but there was no crash, it's a split or bad data. Correct it.

        OUTPUT FORMAT (JSON ONLY):
        [
            {"date": "YYYY-MM-DD", "close": 123.45},
            {"date": "YYYY-MM-DD", "close": 125.10}
        ]
    `;

    try {
        // Add a timeout race to prevent hanging indefinitely
        const timeoutPromise = new Promise((_, reject) => 
            setTimeout(() => reject(new Error("Request timed out")), 25000)
        );

        const apiPromise = client.models.generateContent({
            model: 'gemini-3-flash-preview', 
            contents: prompt,
            config: {
                tools: [{ googleSearch: {} }],
                responseMimeType: 'application/json',
                temperature: 0.0 
            }
        });

        const response: any = await Promise.race([apiPromise, timeoutPromise]);

        const text = response.text;
        if (!text) throw new Error("Empty response");

        const data = parseGeminiJson(text);

        const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
            ?.map((chunk: any) => chunk.web?.uri)
            .filter((uri: string) => !!uri) as string[] || [];

        if (!Array.isArray(data)) throw new Error("Invalid JSON array");

        // Basic validation of content
        const validatedData = data.filter(item => item.date && typeof item.close === 'number');

        if (validatedData.length === 0) throw new Error("No valid data points found");

        const result = { data: validatedData, sources: [...new Set(sources)] };
        CACHE[cacheKey] = result;
        return result;

    } catch (error) {
        console.error("Gemini Data Error:", error);
        // Return empty structure on error to allow UI to degrade gracefully instead of crashing
        return { data: [], sources: [] };
    }
};

