/**
 * Helper to safely parse JSON from LLM response
 */
const parseGeminiJson = (text: string): any => {
    try {
        // 1. Try direct parse
        return JSON.parse(text);
    } catch (e) {
        // 2. Try stripping markdown code blocks
        const markdownRegex = /```(?:json)?([\s\S]*?)```/;
        const match = text.match(markdownRegex);
        if (match && match[1]) {
            try {
                return JSON.parse(match[1].trim());
            } catch (e2) {
                // continue
            }
        }

        // 3. Brute force find array
        try {
            const firstBracket = text.indexOf('[');
            const lastBracket = text.lastIndexOf(']');
            if (firstBracket !== -1 && lastBracket !== -1) {
                const sub = text.substring(firstBracket, lastBracket + 1);
                return JSON.parse(sub);
            }
        } catch (e3) {
            return null;
        }
    }
    return null;
};

/**
 * Fetches historical price data.
 */
export const getGeminiHistory = async (
    ticker: string, 
    currency: string, 
    years: number
): Promise<HistoryResponse> => {

    // Cache key includes timestamp to prevent stale errors during session, 
    // but in a real app we'd want longer caching.
    const cacheKey = `${ticker}-${currency}-${years}-v4`;
    if (CACHE[cacheKey]) {
        return CACHE[cacheKey];
    }

    const client = getClient();
    const today = new Date();
    const endDate = today.toISOString().split('T')[0]; 

    const startDateObj = new Date();
    startDateObj.setFullYear(startDateObj.getFullYear() - years);
    const startDate = startDateObj.toISOString().split('T')[0];

    // Simplified prompt that encourages the model to generate data even if search is imperfect
    const prompt = `
        You are a Financial Data Engine.

        TASK: Get historical price data for ETF "${ticker}" in "${currency}".
        PERIOD: ${startDate} to ${endDate}.

        STEPS:
        1. Use Google Search to find the current price and the 1-year / 3-year history chart for ${ticker}.
        2. Generate a JSON array of about 15-20 data points representing the price trend over this period.
        3. **IMPORTANT**: If you cannot find a downloadable table, you MUST ESTIMATE the monthly points based on the charts/summary found (e.g. 52-week low/high, YTD return). Do not return an error. Provide the best estimation.
        4. Ensure the last point is the latest available price.

        OUTPUT FORMAT:
        Strictly a JSON array of objects. No other text.
        [{"date": "YYYY-MM-DD", "close": 123.45}, ...]
    `;

    try {
        // Increased timeout to 45s for complex reasoning
        const timeoutPromise = new Promise((_, reject) => 
            setTimeout(() => reject(new Error("Request timed out")), 45000)
        );

        const apiPromise = client.models.generateContent({
            model: 'gemini-3-flash-preview', 
            contents: prompt,
            config: {
                tools: [{ googleSearch: {} }],
                // Removed responseMimeType: 'application/json' to avoid conflict with Search tool output handling
                // We will rely on the prompt and regex parsing.
                temperature: 0.1 
            }
        });

        const response: any = await Promise.race([apiPromise, timeoutPromise]);

        const text = response.text;
        if (!text) throw new Error("Empty response from AI");

        // Parse
        const data = parseGeminiJson(text);

        // Extract sources
        const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
            ?.map((chunk: any) => chunk.web?.uri)
            .filter((uri: string) => !!uri) as string[] || [];

        if (!Array.isArray(data)) {
            console.error("Gemini Parse Error. Raw text:", text);
            throw new Error("Could not parse JSON data");
        }

        // Validate
        const validatedData = data.filter(item => item.date && typeof item.close === 'number');

        if (validatedData.length < 2) throw new Error("Insufficient data points found");

        const result = { data: validatedData, sources: [...new Set(sources)] };
        CACHE[cacheKey] = result;
        return result;

    } catch (error) {
        console.error("Gemini Data Error:", error);
        // Throwing allows the UI to show the Error state
        throw error;
    }
};

