/**
 * GEMINI FINANCIAL DATA BRIDGE
 */

const getClient = () => {
    return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
}

export interface HistoryResponse {
    data: { date: string; close: number }[];
    sources: string[];
    isSimulated?: boolean;
}

const CACHE: Record<string, HistoryResponse> = {};

export const getEtfs = async (): Promise<ETF[]> => {
    return new Promise((resolve) => {
        setTimeout(() => resolve(FULL_ETF_UNIVERSE), 50);
    });
};

/**
 * Generates realistic-looking financial data using Geometric Brownian Motion (simplified)
 * Used when API Quota is exceeded so the UI remains functional.
 */
const generateMockData = (ticker: string, years: number): HistoryResponse => {
    const data = [];
    const today = new Date();
    const points = 20 * years; // Approx monthly points
    let price = 100; // Start index at 100

    // Volatility based on ticker "feel"
    let volatility = 0.03; // Default 3% monthly swing
    let trend = 0.006; // Default 0.6% monthly growth (~7% annual)

    if (ticker.includes('BOND') || ticker.includes('AGGH')) { volatility = 0.01; trend = 0.003; }
    if (ticker.includes('QQQ') || ticker.includes('QDVE')) { volatility = 0.05; trend = 0.01; }
    if (ticker.includes('EM')) { volatility = 0.06; trend = 0.004; }

    const startDate = new Date();
    startDate.setFullYear(startDate.getFullYear() - years);

    for (let i = 0; i <= points; i++) {
        const date = new Date(startDate);
        date.setDate(date.getDate() + (i * (365 / points)));

        // Random walk
        const change = (Math.random() - 0.5) * 2 * volatility; 
        price = price * (1 + trend + change);

        data.push({
            date: date.toISOString().split('T')[0],
            close: parseFloat(price.toFixed(2))
        });
    }

    return {
        data: data,
        sources: ['Simulated (API Limit Reached)'],
        isSimulated: true
    };
};

/**
 * Helper to safely parse JSON from LLM response
 */
const parseGeminiJson = (text: string): any => {
    try {
        return JSON.parse(text);
    } catch (e) {
        const markdownRegex = /```(?:json)?([\s\S]*?)```/;
        const match = text.match(markdownRegex);
        if (match && match[1]) {
            try { return JSON.parse(match[1].trim()); } catch (e2) {}
        }
        try {
            const firstBracket = text.indexOf('[');
            const lastBracket = text.lastIndexOf(']');
            if (firstBracket !== -1 && lastBracket !== -1) {
                return JSON.parse(text.substring(firstBracket, lastBracket + 1));
            }
        } catch (e3) {}
    }
    return null;
};

/**
 * Fetches historical price data.
 */
export const getGeminiHistory = async (
    ticker: string, 
    currency: string, 
    years: number
): Promise<HistoryResponse> => {

    const cacheKey = `${ticker}-${currency}-${years}-v5`;
    if (CACHE[cacheKey]) {
        return CACHE[cacheKey];
    }

    try {
        const client = getClient();
        const today = new Date();
        const endDate = today.toISOString().split('T')[0]; 
        const startDateObj = new Date();
        startDateObj.setFullYear(startDateObj.getFullYear() - years);
        const startDate = startDateObj.toISOString().split('T')[0];

        // Lighter prompt to save tokens and reduce complexity
        const prompt = `
            Context: Financial Data for ${ticker} in ${currency}.
            Range: ${startDate} to ${endDate}.
            Task: Provide a JSON array of ~15 monthly historical Adjusted Close prices.

            Rules:
            1. Use Google Search to find a price chart.
            2. Estimate monthly points from the chart.
            3. Return ONLY valid JSON: [{"date":"YYYY-MM-DD","close":123.45},...]
        `;

        // Timeout race - 20s max for better UX
        const timeoutPromise = new Promise((_, reject) => 
            setTimeout(() => reject(new Error("Timeout")), 20000)
        );

        const apiPromise = client.models.generateContent({
            model: 'gemini-3-flash-preview', 
            contents: prompt,
            config: {
                tools: [{ googleSearch: {} }],
                temperature: 0.1 
            }
        });

        const response: any = await Promise.race([apiPromise, timeoutPromise]);

        const text = response.text;
        if (!text) throw new Error("Empty AI response");

        const data = parseGeminiJson(text);

        const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
            ?.map((chunk: any) => chunk.web?.uri)
            .filter((uri: string) => !!uri) as string[] || [];

        if (!Array.isArray(data) || data.length < 2) {
            throw new Error("Invalid data structure");
        }

        const result = { 
            data: data.filter(item => item.date && typeof item.close === 'number'), 
            sources: [...new Set(sources)],
            isSimulated: false
        };

        CACHE[cacheKey] = result;
        return result;

    } catch (error: any) {
        console.warn(`API Error for ${ticker}:`, error.message);

        // FALLBACK: If Quota exceeded, Timeout, or Parse Error -> Return Mock Data
        // This ensures the App NEVER breaks for the user.
        const mock = generateMockData(ticker, years);
        CACHE[cacheKey] = mock; // Cache the mock so we don't retry immediately
        return mock;
    }
};

