/**
 * Fetches historical WEEKLY Adjusted Closing prices via Gemini.
 */
export const getGeminiHistory = async (
    ticker: string, 
    currency: string, 
    years: number
): Promise<HistoryResponse> => {

    const cacheKey = `${ticker}-${currency}-${years}-search-v2`;
    if (CACHE[cacheKey]) {
        return CACHE[cacheKey];
    }

    const client = getClient();
    const today = new Date();
    const endDate = today.toISOString().split('T')[0]; 

    const startDateObj = new Date();
    startDateObj.setFullYear(startDateObj.getFullYear() - years);
    startDateObj.setDate(startDateObj.getDate() - 7); 
    const startDate = startDateObj.toISOString().split('T')[0];

    const prompt = `
        You are a Real-Time Financial Data Retrieval Agent.

        OBJECTIVE: Retrieve ACTUAL historical price data for the ETF "${ticker}" expressed in "${currency}".
        DATE RANGE: ${startDate} to ${endDate}.
        INTERVAL: Weekly (End of week close).

        INSTRUCTIONS:
        1. USE GOOGLE SEARCH to find historical data tables from sources like Stooq, Yahoo Finance, Investing.com.
        2. DATA MATCHING: The user wants the price in ${currency}. If the ETF trades in USD but user wants ${currency}, convert it using historical FX rates or find the local exchange listing (e.g. GPW for PLN).
        3. ACCURACY: The data must match reality.

        OUTPUT FORMAT:
        Return ONLY a JSON array of objects. No markdown.
        [{"date": "2024-01-05", "close": 115.20}, ...]
    `;

    try {
        const response = await client.models.generateContent({
            model: 'gemini-3-flash-preview', 
            contents: prompt,
            config: {
                tools: [{ googleSearch: {} }],
                responseMimeType: 'application/json',
                temperature: 0.1
            }
        });

        const text = response.text;
        if (!text) throw new Error("Empty response from AI");

        const data = JSON.parse(text);

        const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
            ?.map((chunk: any) => chunk.web?.uri)
            .filter((uri: string) => !!uri) as string[] || [];

        if (!Array.isArray(data)) throw new Error("AI did not return an array");

        const result = { data, sources: [...new Set(sources)] };
        CACHE[cacheKey] = result;
        return result;

    } catch (error) {
        console.error("Failed to fetch history from Gemini:", error);
        return { data: [], sources: [] };
    }
};

