/**
 * MATH UTILS: Geometric Brownian Motion Generator
 * Creates a realistic looking stock path between two price points.
 */
const generateBridgePath = (
    startPrice: number, 
    endPrice: number, 
    volatility: number, 
    days: number,
    startDate: Date
) => {
    const prices = [startPrice];
    const dates = [new Date(startDate)];

    const logStart = Math.log(startPrice);
    const logEnd = Math.log(endPrice);
    const driftPerDay = (logEnd - logStart) / days;

    let currentLogPrice = logStart;

    for (let i = 1; i < days; i++) {
        // Random shock (Brownian motion)
        const shock = (Math.random() - 0.5) * 2 * volatility;

        // Add drift and shock
        currentLogPrice += driftPerDay + shock;

        // "Rubber band" correction to ensure we hit the target end price
        const targetLogPriceAtI = logStart + (driftPerDay * i);
        const correction = (targetLogPriceAtI - currentLogPrice) * 0.02; // Gentle correction
        currentLogPrice += correction;

        const date = new Date(startDate);
        date.setDate(date.getDate() + i);

        // Skip weekends
        const dayOfWeek = date.getDay();
        if (dayOfWeek !== 0 && dayOfWeek !== 6) {
             dates.push(date);
             prices.push(Math.exp(currentLogPrice));
        }
    }

    dates.push(new Date(startDate.getTime() + days * 24 * 60 * 60 * 1000));
    prices.push(endPrice);

    return prices.map((p, i) => ({
        date: dates[i] ? dates[i].toISOString().split('T')[0] : new Date().toISOString(),
        close: parseFloat(p.toFixed(2))
    }));
};

/**
 * FALLBACK GENERATOR
 * Used when API Quota is dead. Returns realistic estimates based on Category.
 */
const generateFallbackData = (ticker: string, category: string, years: number): HistoryResponse => {
    // Hardcoded realistic assumptions for Fallback Mode
    let annualReturn = 0.07; // 7% base
    let volatility = 0.010;

    if (category === 'USA S&P500') { annualReturn = 0.105; volatility = 0.012; }
    if (category === 'Tech/Nasdaq') { annualReturn = 0.145; volatility = 0.016; }
    if (category === 'Bonds/Special') { annualReturn = 0.035; volatility = 0.004; }
    if (category === 'Emerging') { annualReturn = 0.055; volatility = 0.014; }
    if (category === 'Europe') { annualReturn = 0.065; volatility = 0.011; }

    // Add some randomness to the return so it's not identical every time
    annualReturn += (Math.random() - 0.5) * 0.02; 

    const days = years * 252;
    const startPrice = 100;
    const endPrice = startPrice * Math.pow((1 + annualReturn), years);

    const startDate = new Date();
    startDate.setFullYear(startDate.getFullYear() - years);

    const data = generateBridgePath(startPrice, endPrice, volatility, days, startDate);

    return {
        data,
        sources: ['Historical Model (API Quota Exceeded)'],
        isSimulated: true,
        performanceMetrics: {
            return1Y: (Math.pow(1+annualReturn, 1) - 1) * 100,
            return3Y: (Math.pow(1+annualReturn, 3) - 1) * 100
        }
    };
};

/**
 * SAFE PARSER
 */
const parseAnchors = (text: string) => {
    try {
        // First try pure JSON parse
        return JSON.parse(text);
    } catch (e) {
        // Try finding JSON block in markdown
        const match = text.match(/```json\s*([\s\S]*?)\s*```/) || text.match(/{[\s\S]*}/);
        if (match) {
            try { return JSON.parse(match[0].replace(/```json|```/g, '')); } catch (e2) {}
        }
    }
    return null;
}

/**
 * MAIN FUNCTION with RETRY LOGIC
 */
export const getGeminiHistory = async (
    ticker: string, 
    currency: string, 
    years: number,
    category: string 
): Promise<HistoryResponse> => {

    const cacheKey = `${ticker}-${currency}-${years}-v4`;
    if (CACHE[cacheKey]) return CACHE[cacheKey];

    const client = getClient();

    // Calculate specific dates for the Prompt
    const now = new Date();
    const dateToday = now.toISOString().split('T')[0];

    const d1 = new Date(); d1.setFullYear(d1.getFullYear() - 1);
    const date1Y = d1.toISOString().split('T')[0];

    const d3 = new Date(); d3.setFullYear(d3.getFullYear() - 3);
    const date3Y = d3.toISOString().split('T')[0];

    const d5 = new Date(); d5.setFullYear(d5.getFullYear() - 5);
    const date5Y = d5.toISOString().split('T')[0];

    const prompt = `
        Task: Find the closing price for ETF "${ticker}" in currency "${currency}".

        Find prices for these specific dates (or the closest trading day):
        1. Current Price (${dateToday})
        2. Price on ${date1Y}
        3. Price on ${date3Y}
        4. Price on ${date5Y}

        Output strictly valid JSON:
        {
          "current": <number>,
          "y1": <number>,
          "y3": <number>,
          "y5": <number>
        }
    `;

    // Retry Logic Loop
    let lastError = null;
    for (let attempt = 0; attempt < 2; attempt++) {
        try {
            // Short delay before retry (exponential backoff)
            if (attempt > 0) await new Promise(r => setTimeout(r, 2000 * attempt));

            // Fast Timeout
            const timeoutMs = 15000;
            const timeoutPromise = new Promise((_, reject) => setTimeout(() => reject(new Error("Timeout")), timeoutMs));

            const apiPromise = client.models.generateContent({
                model: 'gemini-3-flash-preview', 
                contents: prompt,
                config: {
                    tools: [{ googleSearch: {} }],
                    responseMimeType: 'application/json',
                }
            });

            const response: any = await Promise.race([apiPromise, timeoutPromise]);
            const text = response.text;
            const anchors = parseAnchors(text);

            if (!anchors || !anchors.current) throw new Error("Invalid JSON from AI");

            // Build Curve from Anchors
            const start = new Date();
            start.setFullYear(start.getFullYear() - years);

            let startPrice = 100;
            const endPrice = anchors.current;

            if (years <= 1) startPrice = anchors.y1 || endPrice * 0.9;
            else if (years <= 3) startPrice = anchors.y3 || anchors.y1 * 0.8;
            else startPrice = anchors.y5 || anchors.y3 * 0.75;

            // Sanity check
            if (!startPrice || startPrice <= 0) startPrice = endPrice * 0.8;

            let volatility = 0.012;
            if (category.includes('Tech')) volatility = 0.018;

            const data = generateBridgePath(
                startPrice, 
                endPrice, 
                volatility, 
                years * 252, 
                start
            );

            const result = {
                data,
                sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((c: any) => c.web?.uri).filter(Boolean) || [],
                isSimulated: false,
                performanceMetrics: {
                    return1Y: ((anchors.current - (anchors.y1 || anchors.current)) / (anchors.y1 || anchors.current)) * 100,
                    return3Y: ((anchors.current - (anchors.y3 || anchors.current)) / (anchors.y3 || anchors.current)) * 100
                }
            };

            CACHE[cacheKey] = result;
            return result;

        } catch (error: any) {
            console.warn(`Attempt ${attempt + 1} failed for ${ticker}:`, error.message);
            lastError = error;
            // If it's a specific "Quota" error, break immediately and use fallback, don't retry and waste time
            if (error.message && error.message.includes('quota')) break;
        }
    }

    // If all retries failed
    console.error(`All attempts failed for ${ticker}. Using Fallback.`);
    const fallback = generateFallbackData(ticker, category, years);
    CACHE[cacheKey] = fallback; // Cache fallback to prevent rapid re-failures
    return fallback;
};

