};

export default App;

export enum ReplicationMethod {
  PHYSICAL = 'Physical',
  SYNTHETIC = 'Synthetic',
}

export enum DistributionPolicy {
  ACCUMULATING = 'Accumulating',
  DISTRIBUTING = 'Distributing',
}

export type EtfCategory = 'Global' | 'USA S&P500' | 'Tech/Nasdaq' | 'Europe' | 'Emerging' | 'Bonds/Special';

export interface EtfPerformance {
  "1M": number;
  "3M": number;
  "1Y": number;
  "3Y": number;
  "5Y": number;
  source?: string;
  isEstimated: boolean; // True if API failed and we used category average
}

export interface ETF {
  isin: string;
  ticker: string;
  category: EtfCategory;
  name: string;
  issuer: string;
  ter: number; // Total Expense Ratio as percentage
  aum: number; // Assets Under Management in Millions EUR
  currency: string;
  domicile: string;
  replication: ReplicationMethod;
  distribution: DistributionPolicy;
  holdingsCount: number;
  topHoldings: string[];
  description: string;
  dividendYield: number;
}

export interface Broker {
  id: string;
  name: string;
  country: string;
  commissionType: 'Fixed' | 'Variable' | 'Zero';
  commissionRate: number; // percentage
  minCommission: number; // in EUR
  currencyConversionFee: number; // percentage
  isAvailable: boolean;
  notes?: string;
}

import { GoogleGenAI } from '@google/genai';
import { ETF, EtfPerformance } from '../types';

/**
 * GEMINI PERFORMANCE SNAPSHOT SERVICE
 * Replaces heavy historical data fetching with lightweight "Return %" queries.
 */

const getClient = () => {
    return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
}

// Memory Cache to prevent re-fetching the same data
const CACHE: Record<string, EtfPerformance> = {};

