/**
 * AI Analyser Module
 * Handles communication with Google Gemini API to generate structured investment insights.
 */

const getClient = () => {
    if (!process.env.API_KEY) {
        console.warn("API Key is missing. AI features will not work.");
    }
    return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
}

export const analyzeEtfComparison = async (etf1: ETF, etf2: ETF): Promise<AIAnalysisResult | null> => {
  const client = getClient();

  const prompt = `
    You are a Senior Fintech Algo & Investment Analyst. 
    Compare these two ETFs for a long-term (20y+) European investor.

    Asset A: ${etf1.ticker} (${etf1.name}) | TER: ${etf1.ter}% | Domicile: ${etf1.domicile} | Method: ${etf1.replication} | Dist: ${etf1.distribution}
    Asset B: ${etf2.ticker} (${etf2.name}) | TER: ${etf2.ter}% | Domicile: ${etf2.domicile} | Method: ${etf2.replication} | Dist: ${etf2.distribution}

    Output a STRICT JSON object with this specific structure:
    {
      "winnerTicker": "Ticker of the better fund or 'Tie'",
      "confidenceScore": number (0-100),
      "headline": "A short, punchy 1-sentence summary of why one wins (max 10 words)",
      "investmentHorizon": "Recommended holding period (e.g. '10+ Years')",
      "factors": [
        {
          "category": "Cost",
          "winnerTicker": "Ticker or 'Tie'",
          "summary": "Specific analysis of TER and hidden costs."
        },
        {
          "category": "Tax Efficiency",
          "winnerTicker": "Ticker or 'Tie'",
          "summary": "Impact of Domicile and Distribution policy."
        },
        {
          "category": "Diversification",
          "winnerTicker": "Ticker or 'Tie'",
          "summary": "Holdings count and market coverage comparison."
        },
        {
          "category": "Safety",
          "winnerTicker": "Ticker or 'Tie'",
          "summary": "Replication method and Fund Size/Liquidity analysis."
        }
      ],
      "finalVerdict": "A professional paragraph summarizing the strategic advice."
    }
  `;

  try {
    const response = await client.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
      }
    });

    const text = response.text;
    if (!text) return null;

    try {
        const data = JSON.parse(text) as AIAnalysisResult;
        return data;
    } catch (e) {
        console.error("JSON Parse Error", e);
        return null;
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    return null;
  }
};

