            if (isMounted) setPerfRight(p2);

        } catch (err) {
            console.error("Critical Data Error:", err);
        } finally {
            if (isMounted) setIsPerfLoading(false);
        }
    };

    fetchData();

    return () => { isMounted = false; };
  }, [etfLeft, etfRight, currency]);

