    // Mapping ETF keys to Map Regions
    const mapKeys: Record<string, string[]> = {
        'NA': ['USA', 'Canada', 'North America'],
        'EU': ['Europe', 'UK', 'France', 'Germany', 'Italy', 'Spain', 'Switzerland', 'Netherlands', 'Finland'],
